/**
 * WW2 World Map - Country Data with ACTUAL European SVG paths
 * Source: amCharts europeLow.svg (CC BY-NC 4.0)
 * Map focused on WW2-era Europe with accurate country boundaries
 */

export type WW2Faction = 'allies' | 'axis' | 'neutral';
export type CountryStatus = 'free' | 'occupied' | 'annexed';
export type ProgressStatus = 'locked' | 'available' | 'in-progress' | 'complete';

export interface WW2Country {
  id: string;
  name: string;
  svgPath: string;
  faction: WW2Faction;
  status: CountryStatus;
  centerPoint: { x: number; y: number };
  moduleId?: string;
  unlockRequirements?: string[];
  briefDescription: string;
  flagEmoji: string;
  xpAvailable: number;
  estimatedTime: string;
}

export interface WW2MapConfig {
  viewBox: string;
  countries: WW2Country[];
  defaultZoom: number;
  minZoom: number;
  maxZoom: number;
}

