// Helper functions
export function getCountryById(id: string): WW2Country | undefined {
  return WW2_COUNTRIES.find(country => country.id === id);
}

export function getCountriesByFaction(faction: WW2Faction): WW2Country[] {
  return WW2_COUNTRIES.filter(country => country.faction === faction);
}

export function getUnlockedCountries(completedCountries: string[]): string[] {
  return WW2_COUNTRIES
    .filter(country => {
      if (completedCountries.includes(country.id)) return true;
      if (!country.unlockRequirements || country.unlockRequirements.length === 0) return true;
      return country.unlockRequirements.every(req => completedCountries.includes(req));
    })
    .map(country => country.id);
}

export function isCountryLocked(countryId: string, completedCountries: string[]): boolean {
  const country = getCountryById(countryId);
  if (!country) return true;
  if (!country.unlockRequirements || country.unlockRequirements.length === 0) return false;
  return !country.unlockRequirements.every(req => completedCountries.includes(req));
}

export function getTotalXPForFaction(faction: WW2Faction): number {
  return getCountriesByFaction(faction).reduce((sum, country) => sum + country.xpAvailable, 0);
}

export function getProgressForFaction(faction: WW2Faction, completedCountries: string[]): { completed: number; total: number } {
  const factionCountries = getCountriesByFaction(faction);
  const completed = factionCountries.filter(c => completedCountries.includes(c.id)).length;
  return { completed, total: factionCountries.length };
}
